  color: color-mix(in srgb, var(--accent) 74%, white 26%);
  font-size: 0.8rem;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.feature-card {
  --accent: var(--gold);
  display: grid;
  grid-template-columns: minmax(260px, 0.82fr) minmax(0, 1.18fr);
  gap: var(--space-3);
  padding: clamp(1.2rem, 2vw, 1.5rem);
  border: 1px solid color-mix(in srgb, var(--accent) 36%, rgba(255, 255, 255, 0.1));
  border-radius: var(--radius-lg);
  background:
    radial-gradient(circle at top right, color-mix(in srgb, var(--accent) 14%, transparent), transparent 34%),
    linear-gradient(180deg, rgba(255, 255, 255, 0.05), rgba(255, 255, 255, 0.015));
}

.feature-visual {
  position: relative;
  min-height: 300px;
  border-radius: calc(var(--radius-lg) - 8px);
  background:
    linear-gradient(150deg, rgba(255, 255, 255, 0.05), transparent 42%),
    linear-gradient(180deg, rgba(255, 255, 255, 0.05), rgba(255, 255, 255, 0.02));
  overflow: hidden;
}

.visual-ring {
  inset: 8%;
  border: 1px solid rgba(255, 255, 255, 0.12);
}

.visual-dial {
  inset: 18%;
  background:
    radial-gradient(circle at 50% 50%, color-mix(in srgb, var(--accent) 60%, white 40%), transparent 18%),
    radial-gradient(circle at 50% 50%, rgba(255, 255, 255, 0.96), rgba(77, 86, 97, 0.42) 62%, rgba(9, 12, 18, 0.95));
  box-shadow:
    inset 0 0 0 1px rgba(255, 255, 255, 0.24),
    0 24px 46px rgba(0, 0, 0, 0.26);
}

.visual-tag {
  position: absolute;
  right: 1rem;
  bottom: 1rem;
  padding: 0.55rem 0.8rem;
  border-radius: var(--radius-pill);
  background: rgba(6, 10, 15, 0.8);
  border: 1px solid rgba(255, 255, 255, 0.14);
  color: color-mix(in srgb, var(--accent) 78%, white 22%);
  font-size: 0.8rem;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.feature-copy {
  display: grid;
  gap: 0.9rem;
  align-content: center;
}

.feature-meta {
  display: flex;
  flex-wrap: wrap;
  gap: 0.8rem;
  color: var(--gold);
  font-size: 0.82rem;
  font-weight: 800;
  letter-spacing: 0.13em;
  text-transform: uppercase;
}

.feature-tagline {
  color: var(--text);
  font-weight: 700;
}

.feature-design-note {
  padding: 0.95rem 1rem;
  border-left: 2px solid color-mix(in srgb, var(--accent) 72%, white 28%);
  border-radius: 0 var(--radius-md) var(--radius-md) 0;
  background: color-mix(in srgb, var(--accent) 10%, rgba(255, 255, 255, 0.03));
  color: color-mix(in srgb, var(--text) 88%, var(--muted) 12%);
}

.highlight-list {
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
  list-style: none;
}

.highlight-list li {
  padding: 0.6rem 0.85rem;
  border: 1px solid var(--line);
  border-radius: var(--radius-pill);
  background: rgba(255, 255, 255, 0.03);
  color: var(--text);
  font-weight: 600;
}

.spec-grid {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 0.85rem;
}

.spec-grid div {
  padding: 0.95rem;
  border: 1px solid var(--line);
  border-radius: var(--radius-md);
  background: rgba(255, 255, 255, 0.03);
}

.spec-grid dt {
  margin-bottom: 0.35rem;
  color: var(--muted);
  font-size: 0.8rem;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.spec-grid dd {
  margin: 0;
  color: var(--text);
  font-weight: 600;
  line-height: 1.5;
}

.ideal-callout {
  display: grid;
  gap: 0.45rem;
  padding: 1rem 1.05rem;
  border: 1px solid color-mix(in srgb, var(--accent) 32%, rgba(255, 255, 255, 0.08));
  border-radius: var(--radius-md);
  background:
    radial-gradient(circle at top right, color-mix(in srgb, var(--accent) 14%, transparent), transparent 36%),
    rgba(255, 255, 255, 0.03);
}

.ideal-callout span {
  color: color-mix(in srgb, var(--accent) 78%, white 22%);
  font-size: 0.8rem;
  font-weight: 800;
  letter-spacing: 0.14em;
  text-transform: uppercase;
}

.ideal-callout p {
  color: var(--text);
}

.matrix-panel {
  background:
    radial-gradient(circle at 84% 18%, rgba(214, 176, 111, 0.12), transparent 20%),
    linear-gradient(180deg, rgba(9, 15, 24, 0.96), rgba(7, 12, 20, 0.92));
}

.matrix-row {
  display: grid;
  grid-template-columns: minmax(130px, 0.23fr) minmax(0, 0.77fr);
  gap: 1rem;
  padding: 1rem 0;
  border-top: 1px solid var(--line);
}

.matrix-header {
  border-top: 0;
  padding-top: 0.4rem;
}

.matrix-label {
  color: var(--text);
  font-weight: 700;
}

.matrix-values {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 0.9rem;
}

.matrix-values span {
  color: var(--muted);
  line-height: 1.6;
}

.craft-panel {
  background: linear-gradient(180deg, rgba(11, 18, 28, 0.94), rgba(9, 14, 23, 0.9));
}

.pillar-grid {
  grid-template-columns: repeat(3, minmax(0, 1fr));
}

.pillar-card {
  padding: 1.2rem;
  border: 1px solid var(--line);
  border-radius: var(--radius-md);
  background: rgba(255, 255, 255, 0.03);
}

.pillar-card h3 {
  margin-bottom: 0.65rem;
  font-size: 1.4rem;
}

.close-panel {
  display: grid;
  gap: 1rem;
  background:
    radial-gradient(circle at top, rgba(135, 166, 255, 0.12), transparent 28%),
    linear-gradient(180deg, rgba(10, 16, 24, 0.96), rgba(8, 13, 20, 0.92));
}

.close-links a {
  padding: 0.7rem 1rem;
  border: 1px solid var(--line);
  border-radius: var(--radius-pill);
  background: rgba(255, 255, 255, 0.03);
  color: var(--text);
  font-weight: 600;
}

@keyframes rise-in {
  from {
    opacity: 0;
    transform: translateY(22px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@media (max-width: 1100px) {
  .hero-panel,
  .feature-card,
  .section-heading-split {
    grid-template-columns: 1fr;
  }

  .portfolio-grid,
  .pillar-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .credibility-list,
  .spec-grid,
  .matrix-values {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media (max-width: 720px) {
  .page-shell {
    padding-inline: 0.75rem;
  }

